func RandomVector(dim int, seed uint64) TernaryVector {
	rng := NewRNG(seed)
	data := make([]int8, dim)
	for i := range data {
		data[i] = rng.Trit()
	}
	return TernaryVector{Dimension: dim, Data: data}
}

func Bind(a, b TernaryVector) TernaryVector {
	data := make([]int8, a.Dimension)
	for i := range data {
		data[i] = a.Data[i] * b.Data[i]
	}
	return TernaryVector{Dimension: a.Dimension, Data: data}
}

func Unbind(bound, key TernaryVector) TernaryVector {
	return Bind(bound, key)
}

func Bundle3(a, b, c TernaryVector) TernaryVector {
	data := make([]int8, a.Dimension)
	for i := range data {
		s := int16(a.Data[i]) + int16(b.Data[i]) + int16(c.Data[i])
		if s > 0 {
			data[i] = 1
		} else if s < 0 {
			data[i] = -1
		} else {
			data[i] = 0
		}
	}
	return TernaryVector{Dimension: a.Dimension, Data: data}
}

func CosineSimilarity(a, b TernaryVector) float64 {
	dot := 0.0
	normA := 0.0
	normB := 0.0
	for i := 0; i < a.Dimension; i++ {
		ai := float64(a.Data[i])
		bi := float64(b.Data[i])
		dot += ai * bi
		normA += ai * ai
		normB += bi * bi
	}
	if normA == 0 || normB == 0 {
		return 0
	}
	return dot / (math.Sqrt(normA) * math.Sqrt(normB))
}

func Permute(v TernaryVector, k int) TernaryVector {
	d := v.Dimension
	shift := ((k % d) + d) % d
	data := make([]int8, d)
	copy(data, v.Data[shift:])
	copy(data[d-shift:], v.Data[:shift])
	return TernaryVector{Dimension: d, Data: data}
}

