func ProveBindInverse() ProofResult {
	a := RandomVector(ProofDim, 42)
	b := RandomVector(ProofDim, 137)
	bound := Bind(a, b)
	recovered := Unbind(bound, a)
	sim := CosineSimilarity(recovered, b)
	return ProofResult{"bind_inverse", sim > 0.60, 0.60, sim, SimilarityEpsilon}
}

func ProveBindCommutative() ProofResult {
	a := RandomVector(ProofDim, 123)
	b := RandomVector(ProofDim, 456)
	ab := Bind(a, b)
	ba := Bind(b, a)
	ok := true
	for i := range ab.Data {
		if ab.Data[i] != ba.Data[i] {
			ok = false
			break
		}
	}
	actual := 0.0
	if ok {
		actual = 1.0
	}
	return ProofResult{"bind_commutative", ok, 1.0, actual, 0}
}

