func ProveBundleConvergence() ProofResult {
	a := RandomVector(ProofDim, 1001)
	b := RandomVector(ProofDim, 1002)
	c := RandomVector(ProofDim, 1003)
	bundled := Bundle3(a, b, c)
	simA := CosineSimilarity(bundled, a)
	simB := CosineSimilarity(bundled, b)
	simC := CosineSimilarity(bundled, c)
	ok := simA > 0.15 && simB > 0.15 && simC > 0.15
	minSim := math.Min(simA, math.Min(simB, simC))
	return ProofResult{"bundle_convergence", ok, 0.15, minSim, 0.05}
}

func ProveOrthogonality() ProofResult {
	trials := 50
	total := 0.0
	for t := 0; t < trials; t++ {
		a := RandomVector(ProofDim, uint64(10000+t*2))
		b := RandomVector(ProofDim, uint64(10001+t*2))
		total += math.Abs(CosineSimilarity(a, b))
	}
	avg := total / float64(trials)
	return ProofResult{"orthogonality", avg < 0.15, 0.15, avg, 0.05}
}

func ProvePermuteCycle() ProofResult {
	dim := 256
	a := RandomVector(dim, 55)
	k := 17
	p1 := Permute(a, k)
	p2 := Permute(p1, dim-k)
	sim := CosineSimilarity(p2, a)
	return ProofResult{"permute_cycle", math.Abs(sim-1.0) < 0.001, 1.0, sim, 0.001}
}

